"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[67421],{23647:(t,r,e)=>{e.r(r),e.d(r,{data:()=>s});const s={key:"v-547c56da",path:"/%E8%BD%AF%E4%BB%B6/VisualStudio.html",title:"VisualStudio",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"快捷键",slug:"快捷键",children:[{level:3,title:"1.项目相关的快捷键",slug:"_1-项目相关的快捷键",children:[]},{level:3,title:"2.编辑相关的键盘快捷键",slug:"_2-编辑相关的键盘快捷键",children:[]},{level:3,title:"3.导航相关的键盘快捷键",slug:"_3-导航相关的键盘快捷键",children:[]},{level:3,title:"4.调试相关的键盘快捷键",slug:"_4-调试相关的键盘快捷键",children:[]},{level:3,title:"5.搜索相关的键盘快捷键",slug:"_5-搜索相关的键盘快捷键",children:[]}]},{level:2,title:"扩展",slug:"扩展",children:[{level:3,title:"1.vs2019设置默认字符集为UTF8 With BOM",slug:"_1-vs2019设置默认字符集为utf8-with-bom",children:[]},{level:3,title:"2.vs2019高级保存功能",slug:"_2-vs2019高级保存功能",children:[]},{level:3,title:"3.代码辅助工具(ReSharper)",slug:"_3-代码辅助工具-resharper",children:[]},{level:3,title:"4.添加在浏览器中打开功能",slug:"_4-添加在浏览器中打开功能",children:[]}]},{level:2,title:"版本号",slug:"版本号",children:[]},{level:2,title:"其他",slug:"其他",children:[{level:3,title:"VS2019项目模板中没有[ASP.NET空网站]的解决方案",slug:"vs2019项目模板中没有-asp-net空网站-的解决方案",children:[]}]},{level:2,title:"密钥",slug:"密钥",children:[{level:3,title:"2010",slug:"_2010",children:[]}]},{level:2,title:"vs2010打开vs2012",slug:"vs2010打开vs2012",children:[]}],git:{updatedTime:1655693115e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:2}]},filePathRelative:"软件/VisualStudio.md"}},66762:(t,r,e)=>{e.r(r),e.d(r,{default:()=>n});const s=(0,e(57293).uE)('<h1 id="visualstudio" tabindex="-1"><a class="header-anchor" href="#visualstudio" aria-hidden="true">#</a> VisualStudio</h1><h2 id="快捷键" tabindex="-1"><a class="header-anchor" href="#快捷键" aria-hidden="true">#</a> 快捷键</h2><h3 id="_1-项目相关的快捷键" tabindex="-1"><a class="header-anchor" href="#_1-项目相关的快捷键" aria-hidden="true">#</a> 1.<strong>项目相关的快捷键</strong></h3><p><strong>Ctrl + Shift + B</strong> = 生成项目</p><p><strong>Ctrl + Alt + L</strong> = 显示Solution Explorer（解决方案资源管理器）</p><p><strong>Shift + Alt+ C</strong> = 添加新类</p><p><strong>Shift + Alt + A</strong> = 添加新项目到项目</p><h3 id="_2-编辑相关的键盘快捷键" tabindex="-1"><a class="header-anchor" href="#_2-编辑相关的键盘快捷键" aria-hidden="true">#</a> <strong>2.编辑相关的键盘快捷键</strong></h3><p><strong>Ctrl + Enter</strong> = 在当前行插入空行</p><p><strong>Ctrl + Shift + Enter</strong> = 在当前行下方插入空行</p><p><strong>Ctrl +空格键</strong> = 使用IntelliSense（智能感知）自动完成</p><p><strong>Alt + Shift +箭头键</strong>(←,↑,↓,→) = 选择代码的自定义部分</p><p><strong>Ctrl + }</strong> = 匹配大括号、括号</p><p><strong>Ctrl + Shift +}</strong> = 在匹配的括号、括号内选择文本</p><p><strong>Ctrl + Shift + S</strong> = 保存所有文件和项目</p><p><strong>Ctrl + K，Ctrl + C</strong> = 注释选定行</p><p><strong>Ctrl + K，Ctrl + U</strong> = 取消选定行的注释</p><p><strong>Ctrl + K，Ctrl + D</strong> = 正确对齐所有代码</p><p><strong>Shift + End</strong> = 从头到尾选择整行</p><p><strong>Shift + Home</strong> = 从尾到头选择整行</p><p><strong>Ctrl + Delete</strong> = 删除光标右侧的所有字</p><h3 id="_3-导航相关的键盘快捷键" tabindex="-1"><a class="header-anchor" href="#_3-导航相关的键盘快捷键" aria-hidden="true">#</a> <strong>3.导航相关的键盘快捷键</strong></h3><p><strong>Ctrl +Up/Down</strong> = 滚动窗口但不移动光标</p><p><strong>Ctrl + -</strong> = 让光标移动到它先前的位置</p><p><strong>Ctrl ++</strong> = 让光标移动到下一个位置</p><p><strong>F12</strong> = 转到定义</p><h3 id="_4-调试相关的键盘快捷键" tabindex="-1"><a class="header-anchor" href="#_4-调试相关的键盘快捷键" aria-hidden="true">#</a> <strong>4.调试相关的键盘快捷键</strong></h3><p><strong>Ctrl + Alt + P</strong> = 附加到进程</p><p><strong>F10</strong> = 调试单步执行</p><p><strong>F5</strong> = 开始调试</p><p><strong>Shift + F5</strong> = 停止调试</p><p><strong>Ctrl + Alt + Q</strong> = 添加快捷匹配</p><p><strong>F9</strong> = 设置或删除断点</p><h3 id="_5-搜索相关的键盘快捷键" tabindex="-1"><a class="header-anchor" href="#_5-搜索相关的键盘快捷键" aria-hidden="true">#</a> <strong>5.搜索相关的键盘快捷键</strong></h3><p><strong>Ctrl + K Ctrl + K</strong> = 将当前行添加书签</p><p><strong>Ctrl + K Ctrl + N</strong> = 导航至下一个书签</p><p><strong>Ctrl + .</strong> = 如果你键入一个类名如<code>Collection&lt;string&gt;</code>，且命名空间导入不正确的话，那么这个快捷方式组合将自动插入导入</p><p><strong>Ctrl + Shift + F</strong> = 在文件中查找</p><p><strong>Shift + F12</strong> = 查找所有引用</p><p><strong>Ctrl + F</strong> = 显示查找对话框</p><p><strong>Ctrl + H</strong> = 显示替换对话框</p><p><strong>Ctrl + G</strong> = 跳转到行号或行</p><p><strong>Ctrl + Shift + F</strong> = 查找所选条目在整个解决方案中的引用</p><h2 id="扩展" tabindex="-1"><a class="header-anchor" href="#扩展" aria-hidden="true">#</a> 扩展</h2><h3 id="_1-vs2019设置默认字符集为utf8-with-bom" tabindex="-1"><a class="header-anchor" href="#_1-vs2019设置默认字符集为utf8-with-bom" aria-hidden="true">#</a> 1.vs2019设置默认字符集为UTF8 With BOM</h3><p><em>1、扩展》管理扩展》联机-&gt; 搜索 Format On Save 安装；</em><em>2、工具》选项》Format On Save》setting》LineBreak --&gt;选择 windows。</em><em>生效：保存文件扩展即生效。（注意：安装扩展时，有重启 VS2019 的操作）</em></p><h3 id="_2-vs2019高级保存功能" tabindex="-1"><a class="header-anchor" href="#_2-vs2019高级保存功能" aria-hidden="true">#</a> 2.vs2019高级保存功能</h3><ol><li>单击“工具”|“自定义”命令，弹出“自定义”对话框。</li><li>单击“命令”标签，进入“命令”选项卡。</li><li>在“菜单栏”下拉列表中，选择“文件”选项。</li><li>单击“添加命令”按钮，弹出“添加命令”对话框。</li><li>在“类别”列表中，选择“文件”选项；在“命令”列表中，选择“高级保存选项”选项。 单击“确定”按钮，关闭“添加命令”对话框。</li><li>选中“控件”列表中的“高级保存选项”选项，单击“上移”或者“下移”按钮，调整该命令的位置。</li><li>单击“关闭”按钮，完成“高级保存选项”命令的添加操作。</li></ol><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271120542.png" alt="在这里插入图片描述"></p><p><strong>添加高级保存选项</strong></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271120554.png" alt="在这里插入图片描述"></p><p><strong>最后在文件里找到高级保存选项，点开就可以修改编码了。</strong></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271120559.png" alt="在这里插入图片描述"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271120520.png" alt="在这里插入图片描述"></p><h3 id="_3-代码辅助工具-resharper" tabindex="-1"><a class="header-anchor" href="#_3-代码辅助工具-resharper" aria-hidden="true">#</a> 3.代码辅助工具(ReSharper)</h3><p>https://www.it610.com/article/1227730669069766656.htm</p><p>https://www.cnblogs.com/bedfly/p/12295658.html q</p><h3 id="_4-添加在浏览器中打开功能" tabindex="-1"><a class="header-anchor" href="#_4-添加在浏览器中打开功能" aria-hidden="true">#</a> 4.添加在浏览器中打开功能</h3><h2 id="版本号" tabindex="-1"><a class="header-anchor" href="#版本号" aria-hidden="true">#</a> 版本号</h2><p>VC版本 _MSC_VER VS版本 VC6.0 1200 VS 6.0 VC7.0 1300 VS2002 VC7.1 1310 VS2003 VC8.0 1400 VS2005 VC9.0 1500 VS008 VC10.0 1600 VS2010 VC11.0 1700 VS012 VC12.0 1800 VS2013 VC14.0 1900 VS2015</p><h2 id="其他" tabindex="-1"><a class="header-anchor" href="#其他" aria-hidden="true">#</a> 其他</h2><h3 id="vs2019项目模板中没有-asp-net空网站-的解决方案" tabindex="-1"><a class="header-anchor" href="#vs2019项目模板中没有-asp-net空网站-的解决方案" aria-hidden="true">#</a> VS2019项目模板中没有[ASP.NET空网站]的解决方案</h3><p>转自:https://blog.csdn.net/weixin_44527588/article/details/100710791</p><h4 id="一、新建解决方案-课本第十页有教程" tabindex="-1"><a class="header-anchor" href="#一、新建解决方案-课本第十页有教程" aria-hidden="true">#</a> 一、新建解决方案（课本第十页有教程）</h4><h4 id="二、打开新建的解决方案" tabindex="-1"><a class="header-anchor" href="#二、打开新建的解决方案" aria-hidden="true">#</a> 二、打开新建的解决方案</h4><p>1、在项目资源管理器中右击自己创建的解决方案，依次点击添加、新建项目（如图所示）</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271120557.png" alt="在这里插入图片描述"></p><p>在这里插入图片描述</p><h4 id="二、进入项目模板" tabindex="-1"><a class="header-anchor" href="#二、进入项目模板" aria-hidden="true">#</a> 二、进入项目模板</h4><p>1、进入项目模板之后，如果发现自己没有ASP.NET空网站这个模板，则点击安装多个工具和功能（如图所示）</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271120566.png" alt="在这里插入图片描述"></p><p>在这里插入图片描述</p><h4 id="三、进入安装修改界面" tabindex="-1"><a class="header-anchor" href="#三、进入安装修改界面" aria-hidden="true">#</a> 三、进入安装修改界面</h4><p>1、打开ASP.NET和Web开发这个下拉菜单 2、勾选&lt;其他项目模板(早期版本) &gt;这个选项 4、点击修改 5、等待下载安装完成之后就有ASP.NET空网站了 注： 1、所有操作均在连网环境下，因为要下载安装 2、如下载安装完成之后没有ASP.NET空网站，请重启VS2019后再查看。</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271121027.png" alt="在这里插入图片描述"></p><p>在这里插入图片描述</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271120997.png" alt="在这里插入图片描述"></p><h2 id="密钥" tabindex="-1"><a class="header-anchor" href="#密钥" aria-hidden="true">#</a> 密钥</h2><h3 id="_2010" tabindex="-1"><a class="header-anchor" href="#_2010" aria-hidden="true">#</a> 2010</h3><p><strong>YCFHQ-9DWCY-DKV88-T2TMH-G7BHP</strong></p><h2 id="vs2010打开vs2012" tabindex="-1"><a class="header-anchor" href="#vs2010打开vs2012" aria-hidden="true">#</a> vs2010打开vs2012</h2><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271121734.jpeg" alt="img"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271121864.jpeg" alt="img"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271121712.jpeg" alt="img"></p>',84),a={},n=(0,e(63243).Z)(a,[["render",function(t,r){return s}]])},63243:(t,r)=>{r.Z=(t,r)=>{const e=t.__vccOpts||t;for(const[t,s]of r)e[t]=s;return e}}}]);